(window.webpackJsonp=window.webpackJsonp||[]).push([[191],{701:function(_,v,p){"use strict";p.r(v);var t=p(3),e=Object(t.a)({},(function(){var _=this,v=_.$createElement,p=_._self._c||v;return p("ContentSlotsDistributor",{attrs:{"slot-key":_.$parent.slotKey}},[p("p",[_._v("手机早已不是一个单纯的通讯用具，实际上，它已经成为人的一个“器官”。人类给自己创造了一个新的身体：一个新的人和机器的混合体。这个人类的“新器官”是如何被设计出来的？面对苹果近乎完美的iPhone 设计，其他手机的设计师们又是如何应对的？")]),_._v(" "),p("p",[_._v("《外滩画报》记者采访了三星、HTC、诺基亚、微软、小米和联想等手机的设计师们，听他们讲述手机设计中的故事。")]),_._v(" "),p("p",[p("img",{attrs:{src:"http://img.ithome.com/newsuploadfiles/2013/3/20130304_202850_86.jpg",alt:""}})]),_._v(" "),p("p",[_._v("诺基亚设计师的办公桌，摆满了设计稿和蜡模")]),_._v(" "),p("p",[p("img",{attrs:{src:"http://img.ithome.com/newsuploadfiles/2013/3/20130304_202850_183.jpg",alt:""}})]),_._v(" "),p("p",[_._v("诺基亚Lumia设计团队北京分支")]),_._v(" "),p("p",[p("img",{attrs:{src:"http://img.ithome.com/newsuploadfiles/2013/3/20130304_202850_243.jpg",alt:""}})]),_._v(" "),p("p",[_._v("微软移动体验设计总监艾伯特")]),_._v(" "),p("p",[p("img",{attrs:{src:"http://img.ithome.com/newsuploadfiles/2013/3/20130304_202850_339.jpg",alt:""}})]),_._v(" "),p("p",[_._v("小米手机联合创始人兼总设计师刘德")]),_._v(" "),p("p",[p("img",{attrs:{src:"http://img.ithome.com/newsuploadfiles/2013/3/20130304_202850_389.jpg",alt:""}})]),_._v(" "),p("p",[_._v("联想S720手机主持设计的负责人习玮")]),_._v(" "),p("p",[p("strong",[_._v("诺基亚")]),_._v("：")]),_._v(" "),p("p",[_._v("不跟随的设计哲学纯白开放的工作空间，木质装饰和家具，十来个员工各自在电脑上研究概念图，或是在房间入口的小厨房小憩。")]),_._v(" "),p("p",[_._v("办公区域对面有不少独立的小间，以玻璃和外界隔开，里面摆放着各种型号的手机蜡模、色板、工具等等。侯岩江将记者引入其中一小间。")]),_._v(" "),p("p",[_._v("侯岩江是诺基亚 Lumia 设计团队北京分支的高级设计经理，北京分支是全球三大设计团队之一。")]),_._v(" "),p("p",[_._v("“不跟随”战略让诺基亚在智能手机竞争中落入尴尬地位，却让诺基亚在设计中始终保持自我。“我们很注重原创，也会去研究竞争对手的工艺和设计，但一般来说，如果我们采用的工艺传达的信息和其他厂商发生冲突，我们就要警觉，是不是改换一个？”侯岩江说。")]),_._v(" "),p("p",[_._v("侯岩江 11 年前从澳大利亚一所大学毕业后，就一直在诺基亚工作。")]),_._v(" "),p("p",[_._v("“设计一款手机，大体是从确立概念开始，接着是画草图，之后确定材质和工艺，这其中涉及和概念相关的无数试验，最后做各种蜡模，修改成型。从‘酷猎’开始到一款设计最终定型，需要 2-3 年。”侯岩江说。她所在的北京设计团队参加过 Lumia 系列手机以及之前 6600、2630、1100 等型号手机的设计。")]),_._v(" "),p("p",[_._v("在诺基亚工作的设计师，每人都要参加一项奇特的工作：酷猎（Cool Hunting）。")]),_._v(" "),p("p",[_._v("“酷猎”是设计师主导的市场调查。和一般偏重数据和图表分析的调查不同，他们的调查就像采风，找灵感。每一年，诺基亚的设计师会飞到世界各地，拿着手机或相机去拍他们感觉有趣或感动的东西。有一次，她在哥本哈根看到夕阳照在一幢建筑的玻璃上，反射出的光晕，十分迷人，后来就有了诺基亚 6600 玫红色渐变的背板。")]),_._v(" "),p("p",[_._v("有时他们也会入户访谈，用人类学的研究方式走进真正的目标群体。2006 年，侯岩江在印度的小村庄里和当地的妇女聊天，发现那些穿着纱丽身上挂满珠宝的女性却并不喜欢那些华丽的手机，反而更钟爱多功能、科技感十足的新产品。")]),_._v(" "),p("p",[_._v("另一次在德国，他们去柏林典型的中产阶级家庭入户访问，发现人们住着好房子，开着好车，却爱看纸质书，用着特别简单经典的手机。")]),_._v(" "),p("p",[_._v("确立概念后，根据概念选择相应的材质和工艺也是一件极具挑战的工作。“诺基亚 Lumia8 系列确立了极简主义的设计思路，希望和芬兰的设计传统保持一致：简单而富有人情味。于是我们三地的设计团队一直在讨论，如何才能让手机更有手感，更温暖。”侯岩江说。")]),_._v(" "),p("p",[_._v("北欧的工业发展不像德国英国那么快，因此在设计里保留了深厚的手工艺情结。在手机设计上他们打算继承这一点。外壳是一体成型，所有的小零件都是粉末注塑成型的。手机表面的曲面玻璃，是把一块平的玻璃，四周铣出恰到好处的弧度，表面打磨光滑配合曲面，这是他们向手表生产厂商取经的成果，这种工艺很贵，当时一直有争议要不要保留。饱和度极高的机身颜色，也并非喷漆，而是聚碳酸酯材质一体的机身，颜色是材质本身透出来的，即使刮除表层也不会掉色。")]),_._v(" "),p("p",[_._v("“这中间有一段小插曲，市场部反馈说，中国人不喜欢这些颜色，太像玩具了，他们认为中国市场喜欢奢华复杂的感觉，最好是来点金属喷漆或是弄个金色的图案在上面。”她说，“我们当时力排众议，做设计师最痛苦的就是有时候你不得不妥协，而好的设计师知道什么时候该坚持。”上文提到的诺基亚 6600 的渐变背板，是侯岩江自己在欧洲走访了几十家供应商，从一家供应商做的废壳里选定的效果，最后设计师和工程师共同努力，改进技术工艺，最终实现商业化。")]),_._v(" "),p("p",[_._v("在诺基亚，设计师拥有很高的地位，他们常常会不计成本地做一些事情，比如和一些汽车内饰生产商合作，研究把皮质用于手机外壳的实验；和手表生产和珠宝制造家合作，实现一些概念性的想法。前年，诺基亚邀请了英国十个很厉害的珠宝设计师做他们想象的东西，不限于手机也不限于珠宝，有些甚至是雕塑，让他们尝试用不同工艺做出不同的效果。")]),_._v(" "),p("p",[p("strong",[_._v("三星：")])]),_._v(" "),p("p",[_._v("设计与 iPhone 抗衡的手机三星 GALAXY Note II 的设计团队主要有三人：金有兰是 S Pen UX（手写笔用户体验）负责人，郑在雄为高级设计工程师，李贞美则是模型负责人。三个人看起来和韩剧人物别无二致。事实上，他们的神秘性堪比苹果设计师。")]),_._v(" "),p("p",[_._v("自推出以来，三星 GALAXY Note Ⅱ 一路人气高涨，上市短短 2 个月全球销量便以破竹之势突破 500 万台。如今它不仅是全球白领的所爱，更拥有画家、设计师等各类粉丝。")]),_._v(" "),p("p",[_._v("要设计出一款能和 iPhone 抗衡的手机，对于任何一名设计师来说都绝非易事。郑在雄说：“Note 系列的灵感来自记事本和日记本。为此，我买了无数日记本、笔记本，每天都随身携带，不停摩挲。”")]),_._v(" "),p("p",[_._v("后来他发现，比起新的笔记本，棱角略有磨损的旧笔记本更让人舒服。因此在设计手机时，他就用了相对柔和的曲线处理了所有的棱角。")]),_._v(" "),p("p",[_._v("负责手写笔用户体验的金有兰，在设计 GALAXY Note II 时脑海中不断浮现着一个“魔法棒”。这个奇幻“魔法棒”可以让人如同置身童话一样，“看到过去从未见过的东西”。那会是什么呢？在殚思竭虑后，浮窗预览（Air View）、快捷命令（Quick Command）以及随心剪贴（Easy Clip）等创新功能就这么诞生了。")]),_._v(" "),p("p",[_._v("金有兰喜欢反复读《爱丽丝梦游仙境》。“那些奇妙的想象、荒诞的念头、若有若无的秘密以及丝丝入扣的人际关系，让我欲罢不能。”")]),_._v(" "),p("p",[_._v("尤其当灵感枯竭时， 她就马上捧起这本书。")]),_._v(" "),p("p",[_._v("李贞美的眼神看起来比谁都理智。在设计上，她更偏向于实用。“我最喜欢的设计师是维克多·帕帕奈克（Victor Papanek）。他的作品简单实用，充满了人文关怀。” 维克多反对波普的花边和浮华，通常他的设计普通人和残疾人都能用。")]),_._v(" "),p("p",[_._v("李贞美在大学期间，专攻人体行为分析、空间设计以及通用设计领域。当搭档们充满奇思妙想的时候，她首先想到的是“在开发新功能时，得考虑它们是给用户带来便利，还是增加了使用难度？”她认为，如何平衡新功能和操作的人性化是设计过程中最大的困难。")]),_._v(" "),p("p",[_._v("“是的，设计师脑海中的产品构思不仅要和同事们共享，还要让他们和我一起做同样的‘产品梦’，并最终做成商业化的产品。” 金有兰承认这相当艰难，需要不断解决困难。但最终整个团队，还是成功设计出了 GALAXY Note II。")]),_._v(" "),p("p",[p("strong",[_._v("微软：")])]),_._v(" "),p("p",[_._v("用讲故事的方式设计手机艾伯特是微软移动体验设计总监，谈到设计 Windows Phone8 的经历，艾伯特认为最大的亮点就是“打造全新的智能手机操作系统”。")]),_._v(" "),p("p",[_._v("微软是如何设计 Windows Phone8 的？艾伯特透露，微软设计的方法就是讲故事。一开始，“我们先虚构了一个名叫安娜的女主角，她有丈夫和儿子，自己开了一家小型公关公司。”然后，微软几百个设计师针对安娜的生活展开了想象：整整一天中，她会如何使用手机呢？艾伯特的工作间里，挂满了安娜的图像和她生活的各种场景。设计师们还制作了安娜的动画短片。“这让所有人都很兴奋。”")]),_._v(" "),p("p",[_._v("其实，安娜并非凭空想象。“设计前，我们做了大量走访。” 艾伯特说，“我们一直把她当作一个真实人物。”现实中，设计师们的确找到了和安娜相似的人群。他们还邀请后者来到设计室使用原型机、畅谈感受。")]),_._v(" "),p("p",[_._v("关于安娜，艾伯特有一本厚厚的书和图片。但基于商业秘密，他没有提供给《外滩画报》。他指出，这个繁复有趣的过程说明：“微软绝对是按消费者的需求设计手机。”")]),_._v(" "),p("p",[_._v("艾伯特认为，很多厂商在设计手机时一味强调功能，但“设计应该考虑方便生活，比如如何用手机梳理日常事务。” 艾伯特说，Windows Phone8 的很多功能就是方便用户生活的，比如儿童园地功能、圈子功能、日历共享等。只需通过一个简单设置，安娜就可以在手机上激活一个专供孩子玩耍的区域，为孩子量身打造一个专属的开始屏幕，在玩游戏时，他们就不会错发短信打扰到她的同事或者老板，这就是“儿童园地功能”。圈子功能可以让安娜和自己的家人创建私人聊天空间，然后，她可以一边聊天一边共享日程安排、购物清单或照片。")]),_._v(" "),p("p",[_._v("艾伯特认为 Windows Phone 8的开始屏幕还有其具备的动态磁贴（Live Tiles）功能是这款手机最酷的设计。“动态磁贴是精髓。用户可以任意将喜欢的人、应用、音乐、游戏、照片及其他内容固定在开始屏幕，并自定义排序。”")]),_._v(" "),p("p",[_._v("动态磁贴的设计灵感，来源于交通系统中的信号牌。有一天，艾伯特来到上海，当飞机降落到机场时，他看到了机场指示牌。“这个电子板会显示飞机班次信息等。人们只需一眼就能够迅速获得信息。”")]),_._v(" "),p("p",[_._v("而这一瞥之间，给他带了灵感。“何不在手机的开始界面上设计出一个动态磁贴？”")]),_._v(" "),p("p",[_._v("在手机设计的场景中，微软并不刻意强调安娜的性别。“有时候，她使用的方式也有男性特质。”在设计上，艾伯特想突出的是大胆及时尚感。")]),_._v(" "),p("p",[_._v("来微软之前，艾伯特在耐克工作了 11 年。他有许多脍炙人口的作品，比如耐克手表，该表通过软件和硬件的结合测量人们在运动时的生理指标，比如心跳、血压等等。在多年的设计生涯中，艾伯特一直在试图寻找技术和人之间更多互动的可能性。艾伯特心中的偶像是华特迪士尼，“他的设计就有一种人与物、人与产品互动的关系。”")]),_._v(" "),p("p",[p("strong",[_._v("小米：")])]),_._v(" "),p("p",[_._v("做创始人比做设计师快乐小米手机问世超出了所有人的想象。“一开始，我们期待卖 30 万台，但如今它已卖到了 400 万台。”小米手机联合创始人兼总设计师刘德说。")]),_._v(" "),p("p",[_._v("作为小米的总设计师，刘德没有创始人那样的成就感。“作为一个设计师，我过去两年没有一丝快乐。但作为创业者，我非常开心。因为漂亮的销售数据，人们很容易拿小米和大牌比。”小米的供应商 90% 和 iPhone 是重叠的，“所以大家对小米的ID(工业设计)的要求也如此。”结果，网上就出现了这样的评价——“小米的设计师是来打酱油的。”")]),_._v(" "),p("p",[_._v("刘德不郁闷。“作为初创公司，站在一个创始人的角度，我太知道一个设计总监需要何种妥协了。小米能做成，就是在不断违背行业规律。”")]),_._v(" "),p("p",[_._v("至今，小米生产了两代机型。而刘德领导的设计部只有四个人，全部都是他精挑细选来的。“我一定要用熟手，至少十年以上，而且不要大公司的。因为大公司的设计师一年需要三个月假期去全世界找灵感，小米陪不起。”")]),_._v(" "),p("p",[_._v("“我挑人的逻辑是作品收敛、成熟，而且还要能吃苦。”刘德表示，“如果一开始你就在大公司，各方面都配合你做设计，来小米就不合适。”因为小米在刚创业时，几乎所有供应商都爱理不理的。何况，刘德和雷军一上来“就要颠覆”，其战略定位在“主打发烧友”。")]),_._v(" "),p("p",[_._v("最大的压力并非人力，而是时间。既然小米是发烧型机器，“你就得最大限度追赶技术和配置。”结果，直到最后阶段决策层才知道完美产品的定义，但这给设计带来的就是留出来的时间会非常短。留给刘德的时间每次都只有一个月，这远远低于手机设计的传统。“一般是十几周。”而当机型最终面世时，“可能和最初的设想相去甚远。”")]),_._v(" "),p("p",[_._v("所有人都在往前跑，其中技术起到了决定作用——手机供应商、芯片技术的每一次翻新，都导致所有厂商不停地追逐")]),_._v(" "),p("p",[_._v("出处："),p("a",{attrs:{href:"http://www.bundpic.com/2013/02/21006.shtml",target:"_blank",rel:"noopener noreferrer"}},[_._v("外滩画报"),p("OutboundLink")],1),_._v("    作者：李卉 华琪")])])}),[],!1,null,null,null);v.default=e.exports}}]);